1	import type { CliqueSummary } from "@/lib/api/types";
2	
3	export interface GraphEdge {
4	  source: string;
5	  target: string;
6	}
7	
8	/**
9	 * Derive undirected edges from clique co-membership.
10	 * Any two nodes sharing a clique get an edge.
11	 * Edges are deduplicated (sorted pair key).
12	 */
13	export function deriveEdgesFromCliques(cliques: CliqueSummary[]): GraphEdge[] {
14	  const seen = new Set<string>();
15	  const edges: GraphEdge[] = [];
16	
17	  for (const clique of cliques) {
18	    const nodes = clique.nodes;
19	    for (let i = 0; i < nodes.length; i++) {
20	      for (let j = i + 1; j < nodes.length; j++) {
21	        const a = nodes[i]!;
22	        const b = nodes[j]!;
23	        const key = a < b ? `${a}::${b}` : `${b}::${a}`;
24	        if (!seen.has(key)) {
25	          seen.add(key);
26	          edges.push({ source: a, target: b });
27	        }
28	      }
29	    }
30	  }
31	
32	  return edges;
33	}
34	
35	/**
36	 * Merge clique-derived edges with optional conditional edges.
37	 * Conditional edges are directional (from -> to) but stored in the same format.
38	 */
39	export function mergeEdges(
40	  cliqueEdges: GraphEdge[],
41	  conditionalEdges: Array<{ from: string; to: string }> = [],
42	): GraphEdge[] {
43	  const seen = new Set<string>(
44	    cliqueEdges.map((e) => {
45	      const a = typeof e.source === "string" ? e.source : e.source;
46	      const b = typeof e.target === "string" ? e.target : e.target;
47	      return a < b ? `${a}::${b}` : `${b}::${a}`;
48	    }),
49	  );
50	
51	  const merged = [...cliqueEdges];
52	
53	  for (const ce of conditionalEdges) {
54	    const key = ce.from < ce.to ? `${ce.from}::${ce.to}` : `${ce.to}::${ce.from}`;
55	    if (!seen.has(key)) {
56	      seen.add(key);
57	      merged.push({ source: ce.from, target: ce.to });
58	    }
59	  }
60	
61	  return merged;
62	}
