239	  focusMarketId,
240	  conditionalEdges = [],
241	}: BayesNetGraphProps) {
242	  const { data: marketsData, isLoading } = useMarkets();
243	  const { data: engineStats } = useEngineStats(focusMarketId ?? "", { enabled: !!focusMarketId });
244	
245	  const markets = marketsData?.markets ?? [];
246	  const nodes = useMemo(() => layoutNodes(markets), [markets]);
247	  const cliques = engineStats?.cliques.cliques ?? [];
248	
249	  // --- Animation: detect assumption changes and trigger propagation ---
250	  const { assumptions } = useAssumptions();
251	  const { animatingNodes, animatingEdges, evidenceNodeId, triggerAnimation, cancelAnimation } =
252	    useAnimationPropagation();
253	  const prevAssumptionsRef = useRef(assumptions);
254	
255	  // Derive all edges for BFS traversal (clique-derived + conditional)
256	  const allEdges = useMemo(
257	    () => mergeEdges(deriveEdgesFromCliques(cliques), conditionalEdges),
258	    [cliques, conditionalEdges],
259	  );
260	
261	  useEffect(() => {
262	    const prev = prevAssumptionsRef.current;
263	    prevAssumptionsRef.current = assumptions;
264	
265	    if (prev === assumptions) return;
266	
267	    // Find the assumption that was added or removed
268	    const added = assumptions.find(
269	      (a) => !prev.some((p) => p.variableId === a.variableId && p.outcomeId === a.outcomeId),
270	    );
271	    const removed = prev.find(
272	      (p) => !assumptions.some((a) => a.variableId === p.variableId && a.outcomeId === p.outcomeId),
273	    );
274	
275	    const changedVariableId = added?.variableId ?? removed?.variableId;
276	    if (!changedVariableId) return;
277	
278	    // Find the node (market) that corresponds to the changed variable
279	    const evidenceNode = markets.find((m) => m.variableId === changedVariableId);
280	    if (evidenceNode && allEdges.length > 0) {
281	      triggerAnimation(evidenceNode.id, allEdges);
282	    }
283	  }, [assumptions, markets, allEdges, triggerAnimation]);
284	
285	  // Cancel animation on unmount
286	  useEffect(() => cancelAnimation, [cancelAnimation]);
287	
288	  if (isLoading) {
289	    return (
290	      <div style={panelStyle}>
291	        <div style={{ color: "var(--color-text-muted)", textAlign: "center", padding: "var(--space-lg)" }}>
292	          Loading network...
293	        </div>
294	      </div>
295	    );
296	  }
297	
298	  if (markets.length === 0) {
299	    return (
300	      <div style={panelStyle}>
301	        <div style={{ color: "var(--color-text-muted)", textAlign: "center" }}>
302	          No markets to visualize.
303	        </div>
304	      </div>
305	    );
306	  }
307	
308	  // Compute SVG viewBox from node positions
309	  const xs = nodes.map((n) => n.x);
310	  const ys = nodes.map((n) => n.y);
311	  const vbX = Math.min(...xs) - NODE_W / 2 - PADDING;
312	  const vbY = Math.min(...ys) - NODE_H / 2 - PADDING;
313	  const vbW = Math.max(...xs) - Math.min(...xs) + NODE_W + PADDING * 2;
314	  const vbH = Math.max(...ys) - Math.min(...ys) + NODE_H + PADDING * 2;
315	
316	  return (
317	    <div style={panelStyle}>
318	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-sm)" }}>
319	        <h3 style={{ fontSize: "1rem", fontWeight: 600 }}>
320	          Bayesian Network
321	        </h3>
322	        <div style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
323	          {markets.length} variable{markets.length !== 1 ? "s" : ""}
324	          {conditionalEdges.length > 0 && ` · ${conditionalEdges.length} edge${conditionalEdges.length !== 1 ? "s" : ""}`}
325	          {cliques.length > 0 && ` · ${cliques.length} clique${cliques.length !== 1 ? "s" : ""}`}
326	          {engineStats && ` · JT width ${engineStats.cliques.junction_tree_width}`}
327	        </div>
328	      </div>
329	
330	      <svg
331	        viewBox={`${vbX} ${vbY} ${vbW} ${vbH}`}
332	        style={{ width: "100%", height: "auto", minHeight: 200, maxHeight: 400 }}
333	      >
334	        <defs>
335	          {/* Glow filter for evidence node */}
336	          <filter id="evidence-glow" x="-30%" y="-30%" width="160%" height="160%">
337	            <feGaussianBlur in="SourceAlpha" stdDeviation="6" result="blur" />
338	            <feFlood floodColor="var(--color-primary)" floodOpacity="0.6" result="color" />
339	            <feComposite in="color" in2="blur" operator="in" result="glow" />
340	            <feMerge>
341	              <feMergeNode in="glow" />
342	              <feMergeNode in="SourceGraphic" />
343	            </feMerge>
344	          </filter>
345	          {/* Highlight filter for nodes reached by propagation wave */}
346	          <filter id="propagation-highlight" x="-15%" y="-15%" width="130%" height="130%">
347	            <feDropShadow dx="0" dy="0" stdDeviation="4" floodColor="var(--color-info)" floodOpacity="0.5" />
348	          </filter>
349	        </defs>
350	        <style>{`
351	          @keyframes evidence-pulse {
352	            0% { opacity: 0.7; }
353	            50% { opacity: 1; }
354	            100% { opacity: 0.7; }
355	          }
356	          @keyframes propagation-arrive {
357	            0% { opacity: 0; transform: scale(0.95); }
358	            50% { opacity: 1; transform: scale(1.02); }
359	            100% { opacity: 1; transform: scale(1); }
360	          }
361	          @keyframes edge-flow {
362	            0% { stroke-dashoffset: 16; }
363	            100% { stroke-dashoffset: 0; }
364	          }
365	          .evidence-node { animation: evidence-pulse 0.8s ease-in-out infinite; filter: url(#evidence-glow); }
366	          .propagation-node { animation: propagation-arrive 0.3s ease-out forwards; filter: url(#propagation-highlight); }
367	          .propagation-edge { animation: edge-flow 0.4s linear infinite; }
368	        `}</style>
369	
370	        {/* Clique overlays (behind edges/nodes) */}
371	        {cliques.map((c) => (
372	          <CliqueOverlay key={c.id} clique={c} nodes={nodes} />
373	        ))}
374	
375	        {/* Conditional edges */}
376	        {conditionalEdges.map((e, i) => (
