383	          if (!animatingEdges.has(ek)) return null;
384	          const a = nodes.find((n) => n.id === e.source);
385	          const b = nodes.find((n) => n.id === e.target);
386	          if (!a || !b) return null;
387	          const dx = b.x - a.x;
388	          const dy = b.y - a.y;
389	          const dist = Math.sqrt(dx * dx + dy * dy);
390	          if (dist === 0) return null;
391	          const ux = dx / dist;
392	          const uy = dy / dist;
393	          const sx = a.x + ux * (NODE_W / 2 + 4);
394	          const sy = a.y + uy * (NODE_H / 2 + 4);
395	          const ex = b.x - ux * (NODE_W / 2 + 8);
396	          const ey = b.y - uy * (NODE_H / 2 + 8);
397	          return (
398	            <line
399	              key={`anim-${ek}`}
400	              x1={sx} y1={sy} x2={ex} y2={ey}
401	              stroke="var(--color-info)"
402	              strokeWidth={2.5}
403	              strokeDasharray="8 8"
404	              opacity={0.8}
405	              className="propagation-edge"
406	            />
407	          );
408	        })}
409	
410	        {/* Market nodes */}
411	        {nodes.map((node) => {
412	          const isEvidence = node.id === evidenceNodeId;
413	          const isAnimating = animatingNodes.has(node.id);
414	          const animClass = isEvidence
415	            ? "evidence-node"
416	            : isAnimating
417	              ? "propagation-node"
418	              : undefined;
419	          return (
420	            <NodeWithDetail
421	              key={node.id}
422	              node={node}
423	              isFocus={node.id === focusMarketId}
424	              animationClass={animClass}
425	            />
426	          );
427	        })}
428	      </svg>
429	
430	      {/* Legend */}
431	      <div style={{ display: "flex", gap: "var(--space-md)", fontSize: "0.75rem", color: "var(--color-text-muted)", marginTop: "var(--space-sm)" }}>
432	        <span>
433	          <span style={{ display: "inline-block", width: 8, height: 8, borderRadius: "50%", background: "var(--color-success)", marginRight: 4 }} />
434	          Active
435	        </span>
436	        <span>
437	          <span style={{ display: "inline-block", width: 8, height: 8, borderRadius: "50%", background: "var(--color-info)", marginRight: 4 }} />
438	          Resolved
439	        </span>
