441	          <span>
442	            <span style={{ display: "inline-block", width: 16, height: 2, background: "var(--color-primary)", marginRight: 4, verticalAlign: "middle" }} />
443	            Conditional dependency
444	          </span>
445	        )}
446	        {cliques.length > 0 && (
447	          <span>
448	            <span style={{ display: "inline-block", width: 12, height: 12, border: "1px dashed var(--color-primary)", borderRadius: 3, marginRight: 4, verticalAlign: "middle", opacity: 0.5 }} />
449	            Junction tree clique
